const config = $input.first().json;
const base = config.GitRawBaseURL;
const branch = config.GitBranch || 'dev/breaks-recovery';
const path = config.MappingsPath || 'BreaksRecovery_Main/mappings';

if (!base) {
  throw new Error(
    'System Error: GitRawBaseURL не задан. TDR v3 §6.5: маппинги загружаются из git (stash). Укажите URL raw-файлов в GetConfig.',
  );
}

const files = [
  'activity',
  'container',
  'news_reading',
  'news_exception_skills',
  'fte_groups',
  'email_fallback',
  'fte_thresholds',
  'runtime',
];

const mappings = {};

for (const file of files) {
  const url = `${String(base).replace(/\/$/, '')}/${branch}/${path}/${file}.json`;
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(`System Error: не удалось загрузить ${file}.json (${response.status}) из ${url}`);
  }
  mappings[file] = await response.json();
}

return [
  {
    json: {
      ...config,
      mappings,
      mappings_loaded_at: new Date().toISOString(),
    },
  },
];
